{%- macro en_palabras(numero) -%}
{%- set n = numero | int -%}
{%- set decimales = ((numero - n) * 100) | round | int -%}
{%- set unidades = ['','UN','DOS','TRES','CUATRO','CINCO','SEIS','SIETE','OCHO','NUEVE','DIEZ','ONCE','DOCE','TRECE','CATORCE','QUINCE','DIECISÉIS','DIECISIETE','DIECIOCHO','DIECINUEVE','VEINTE'] -%}
{%- set decenas = ['','DIEZ','VEINTE','TREINTA','CUARENTA','CINCUENTA','SESENTA','SETENTA','OCHENTA','NOVENTA'] -%}
{%- set centenas = ['','CIENTO','DOSCIENTOS','TRESCIENTOS','CUATROCIENTOS','QUINIENTOS','SEISCIENTOS','SETECIENTOS','OCHOCIENTOS','NOVECIENTOS'] -%}
{%- macro tres_cifras(x) -%}
  {%- set c = (x / 100) | int -%}
  {%- set resto = x % 100 -%}
  {%- set d = (resto / 10) | int -%}
  {%- set u = resto % 10 -%}
  {%- if c == 1 and resto == 0 -%}CIEN
  {%- elif c > 0 -%}{{ centenas[c] }}{% if resto > 0 %} {% endif %}
  {%- endif -%}
  {%- if resto <= 20 -%}{{ unidades[resto] }}
  {%- elif resto > 20 -%}
    {{ decenas[d] }}{% if u > 0 %} Y {{ unidades[u] }}{% endif %}
  {%- endif -%}
{%- endmacro -%}
{%- if n == 0 -%}CERO
{%- elif n < 0 -%}MENOS {{ en_palabras(-n) }}
{%- else -%}
  {%- set miles = (n / 1000) | int -%}
  {%- set resto_miles = n % 1000 -%}
  {%- if miles == 1 -%}UN MIL
  {%- elif miles > 1 -%}{{ tres_cifras(miles) }} MIL
  {%- endif -%}
  {%- if miles > 0 and resto_miles > 0 %} {% endif -%}
  {%- if resto_miles > 0 -%}{{ tres_cifras(resto_miles) }}{%- endif -%}
{%- endif -%}
{%- if decimales > 0 %} CON {{ '%02d' | format(decimales) }}/100{%- endif -%}
{%- endmacro -%}

{%- macro mes_en_palabras(fecha_str) -%}
{%- set fecha = frappe.utils.getdate(fecha_str) -%}
{%- set meses = ['','ENERO','FEBRERO','MARZO','ABRIL','MAYO','JUNIO','JULIO','AGOSTO','SEPTIEMBRE','OCTUBRE','NOVIEMBRE','DICIEMBRE'] -%}
{{ meses[fecha.month] }}
{%- endmacro -%}

{%- macro anio_en_palabras_macro(anio) -%}
{%- set unidades = ['','UN','DOS','TRES','CUATRO','CINCO','SEIS','SIETE','OCHO','NUEVE','DIEZ','ONCE','DOCE','TRECE','CATORCE','QUINCE','DIECISÉIS','DIECISIETE','DIECIOCHO','DIECINUEVE','VEINTE'] -%}
{%- set decenas_txt = ['','','VEINTI','TREINTA','CUARENTA','CINCUENTA','SESENTA','SETENTA','OCHENTA','NOVENTA'] -%}
{%- set miles = (anio / 1000) | int -%}
{%- set resto = anio % 1000 -%}
{%- set centenas_val = (resto / 100) | int -%}
{%- set resto2 = resto % 100 -%}
{%- if miles == 2 %}DOS MIL{% endif %}
{%- if centenas_val > 0 %} {{ ['','CIENTO','DOSCIENTOS','TRESCIENTOS','CUATROCIENTOS','QUINIENTOS','SEISCIENTOS','SETECIENTOS','OCHOCIENTOS','NOVECIENTOS'][centenas_val] }}{% endif %}
{%- if resto2 > 0 %} {{ unidades[resto2] if resto2 <= 20 else (decenas_txt[(resto2/10)|int] + (unidades[resto2%10] if resto2%10 > 0 else '')) }}{% endif %}
{%- endmacro -%}

{%- macro numero_lote_palabras(lote) -%}
{%- set partes = lote.split('-') -%}
{%- set letra = partes[0] -%}
{%- set num = partes[1] | int if partes | length > 1 else 0 -%}
{%- set ordinales = ['','UNO','DOS','TRES','CUATRO','CINCO','SEIS','SIETE','OCHO','NUEVE','DIEZ','ONCE','DOCE','TRECE','CATORCE','QUINCE','DIECISÉIS','DIECISIETE','DIECIOCHO','DIECINUEVE','VEINTE','VEINTIUNO','VEINTIDÓS','VEINTITRÉS','VEINTICUATRO','VEINTICINCO','VEINTISÉIS','VEINTISIETE','VEINTIOCHO','VEINTINUEVE','TREINTA'] -%}
{{ letra }}-{{ ordinales[num] if num <= 30 else num }} ({{ lote }})
{%- endmacro -%}

<style>
