  .clausula { font-weight: bold; margin-top: 16px; margin-bottom: 4px; }
  p { text-align: justify; margin-bottom: 8px; }
  .firma-seccion { margin-top: 60px; }
  .firma-contenedor { display: flex; justify-content: space-between; margin-top: 40px; }
  .firma-bloque { text-align: center; width: 45%; }
  .firma-linea { border-top: 1px solid #000; margin-bottom: 6px; }
  .firma-nombre { font-weight: bold; }
  .tabla-modelo { width: 60%; margin: 10px auto; border-collapse: collapse; }
  .tabla-modelo td, .tabla-modelo th { border: 1px solid #ccc; padding: 4px 10px; }
