{%- macro fmt(n) -%}
{%- set n = n | float -%}
{%- set neg = n < 0 -%}
{%- set n = -n if neg else n -%}
{%- set dec = ((n - (n | int)) * 100) | round | int -%}
{%- set entero = n | int -%}
{%- set miles = (entero / 1000) | int -%}
{%- set resto = entero % 1000 -%}
{%- if neg %}-{% endif -%}
{%- if miles > 0 %}{{ miles }},{{ "%03d" | format(resto) }}{% else %}{{ entero }}{% endif %}.{{ "%02d" | format(dec) }}
{%- endmacro -%}

<style>
  body { font-family: Arial, sans-serif; font-size: 10pt; color: #000; line-height: 1.4; }
  .doc { max-width: 780px; margin: 0 auto; padding: 24px 40px; }
  .empresa { text-align: center; margin-bottom: 4px; }
  .empresa h2 { font-size: 13pt; font-weight: 700; margin: 0; text-transform: uppercase; }
  .empresa h3 { font-size: 11pt; font-weight: 600; margin: 2px 0; }
  .empresa h1 { font-size: 12pt; font-weight: 700; margin: 4px 0 12px; text-decoration: underline; text-transform: uppercase; }
  .info-grid { width: 100%; border-collapse: collapse; margin-bottom: 12px; }
  .info-grid td { padding: 3px 6px; font-size: 10pt; }
  .info-grid .lbl { font-weight: 700; width: 220px; }
  .info-grid .val { border-bottom: 1px solid #000; min-width: 180px; }
  .precio-total { width: 100%; border-collapse: collapse; margin-bottom: 12px; }
  .precio-total td { padding: 4px 6px; }
  .precio-total .lbl { font-weight: 700; font-size: 11pt; }
  .precio-total .val { font-weight: 700; font-size: 11pt; text-align: right; border-bottom: 2px solid #000; }
  table.main { width: 100%; border-collapse: collapse; margin-bottom: 8px; border: 1px solid #000; }
  table.main th { background: #d0d0d0; font-weight: 700; padding: 5px 8px; border: 1px solid #000; font-size: 10pt; text-align: left; }
  table.main th.right { text-align: right; }
  table.main td { padding: 4px 8px; border: 1px solid #ccc; font-size: 10pt; }
  table.main td.right { text-align: right; }
  table.main td.center { text-align: center; }
  table.main tr.seccion td { background: #e8e8e8; font-weight: 700; text-transform: uppercase; font-size: 10pt; border: 1px solid #000; }
  table.main tr.seccion-credito td { background: #e8f5e9; font-weight: 700; text-transform: uppercase; font-size: 10pt; border: 1px solid #000; color: #2e7d32; }
  table.main tr.subtotal td { font-weight: 700; background: #f0f0f0; border-top: 1px solid #000; }
  table.main tr.subtotal-credito td { font-weight: 700; background: #e8f5e9; border-top: 1px solid #000; color: #2e7d32; }
  table.main tr.credito-row td { color: #2e7d32; }
  table.main tr.total-final td { font-weight: 700; font-size: 11pt; background: #d0d0d0; border: 1px solid #000; }
  .pie { margin-top: 12px; font-size: 9.5pt; }
  .pie-flex { display: flex; justify-content: space-between; margin-top: 6px; }
  .nota { font-style: italic; font-size: 9pt; color: #444; margin-top: 4px; }
</style>

<div class="doc">

  {%- set lote_doc = frappe.get_doc("Lotes", doc.lote) if doc.lote else None -%}

  <div class="empresa">
    <h2>INVERSIONES BEL S.A.</h2>
    <h3>{{ doc.proyecto }}</h3>
    <h1>Proforma de Construcción</h1>
  </div>

  <table class="info-grid">
    <tr>
      <td class="lbl">LOTE</td>
      <td class="val">{{ lote_doc.numero_lote if lote_doc else doc.lote }}</td>
      <td width="40"></td>
      <td class="lbl">MODELO</td>
      <td class="val">{{ doc.modelo | upper }}</td>
    </tr>
    <tr>
      <td class="lbl">ÁREA CONSTRUCCIÓN M²</td>
      <td class="val">{{ lote_doc.m2_casa if lote_doc else '—' }} mts²</td>
      <td></td>
      <td class="lbl">ÁREA DE TERRENO</td>
      <td class="val">{{ lote_doc.v2_terreno if lote_doc else '—' }} vrs²</td>
    </tr>
    <tr>
      <td class="lbl">CLIENTE</td>
      <td class="val" colspan="4">{{ doc.comprador | upper }}</td>
    </tr>
    <tr>
      <td class="lbl">FECHA</td>
      <td class="val" colspan="4">{{ frappe.utils.formatdate(doc.fecha) }}</td>
    </tr>
  </table>

  <table class="precio-total">
    <tr>
      <td class="lbl">PRECIO TOTAL A PAGAR</td>
      <td class="val">U$ {{ fmt(doc.total) }}</td>
    </tr>
  </table>

  <table class="main">
    <thead>
      <tr>
        <th>DESCRIPCIÓN</th>
        <th class="right" style="width:80px;">CANTIDAD</th>
        <th class="right" style="width:100px;">P/U</th>
        <th class="right" style="width:100px;">TOTAL</th>
      </tr>
    </thead>
    <tbody>

      {%- set base = doc.extras | selectattr("seccion", "equalto", "Base") | list -%}
      {%- if base -%}
      {%- for row in base -%}
      <tr>
        <td>{{ row.descripcion or '' }}</td>
        <td class="center">{{ row.cantidad or '' }}</td>
        <td class="right">{{ fmt(row.monto or 0) }}</td>
        <td class="right">{{ fmt((row.monto or 0) * (row.cantidad or 1)) }}</td>
      </tr>
      {%- endfor -%}
      <tr class="subtotal">
        <td colspan="3">TOTAL</td>
        <td class="right">{{ fmt(base | sum(attribute="monto")) }}</td>
      </tr>
      {%- endif -%}

      {%- set adicionales = doc.extras | selectattr("seccion", "equalto", "Adicional") | list -%}
      {%- if adicionales -%}
      <tr class="seccion"><td colspan="4">ADICIONALES</td></tr>
      {%- for row in adicionales -%}
      <tr>
        <td>{{ row.descripcion or '' }}</td>
        <td class="center">{{ row.cantidad or '' }}</td>
        <td class="right">{{ fmt(row.monto or 0) }}</td>
        <td class="right">{{ fmt((row.monto or 0) * (row.cantidad or 1)) }}</td>
      </tr>
      {%- endfor -%}
      <tr class="subtotal">
        <td colspan="3">TOTAL</td>
        <td class="right">{{ fmt(adicionales | sum(attribute="monto")) }}</td>
      </tr>
      {%- endif -%}

      {%- set creditos = doc.extras | selectattr("seccion", "equalto", "Crédito") | list -%}
      {%- if creditos -%}
      <tr class="seccion-credito">
        <td>CRÉDITOS (A FAVOR DEL CLIENTE)</td>
        <td class="right">CANTIDAD</td>
        <td class="right">P/U</td>
        <td class="right">TOTAL</td>
      </tr>
      {%- for row in creditos -%}
      <tr class="credito-row">
        <td>{{ row.descripcion or '' }}</td>
        <td class="center">{{ row.cantidad or '' }}</td>
        <td class="right">{{ fmt(row.monto or 0) }}</td>
        <td class="right">{{ fmt((row.monto or 0) * (row.cantidad or 1)) }}</td>
      </tr>
      {%- endfor -%}
      <tr class="subtotal-credito">
        <td colspan="3">SUB TOTAL CRÉDITOS</td>
        <td class="right">{{ fmt(creditos | sum(attribute="monto")) }}</td>
      </tr>
      {%- endif -%}

      {%- if doc.descuento_especial and doc.descuento_especial > 0 -%}
      <tr>
        <td colspan="3"><strong>DESCUENTO ESPECIAL</strong></td>
        <td class="right"><strong>{{ fmt(doc.descuento_especial) }}</strong></td>
      </tr>
      {%- endif -%}

      <tr class="total-final">
        <td colspan="3">TOTAL</td>
        <td class="right">U$ {{ fmt(doc.total) }}</td>
      </tr>

    </tbody>
  </table>

  <div class="pie">
    <div class="pie-flex">
      <div>
        <p><strong>Asesor:</strong> {{ doc.asesor or '—' }}</p>
        <p class="nota">Proforma válida por {{ doc.valido_por or 6 }} días</p>
        <p class="nota">Esto no es una reserva</p>
      </div>
      <div style="text-align:right;">
        <p><strong>Revisado por:</strong> {{ doc.revisado_por or '—' }}</p>
        <p><strong>Fecha:</strong> {{ frappe.utils.formatdate(doc.fecha) }}</p>
      </div>
    </div>
  </div>

</div>
